import{_ as e,o as d,c as a,ag as i}from"./chunks/framework.Vng7Hdlh.js";const b=JSON.parse('{"title":"21. Stripe決済の全設定（完全ガイド）","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/21-stripe-full.md","filePath":"tenant/21-stripe-full.md"}'),r={name:"tenant/21-stripe-full.md"};function l(o,t,n,s,p,h){return d(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="_21-stripe決済の全設定-完全ガイド" tabindex="-1">21. Stripe決済の全設定（完全ガイド） <a class="header-anchor" href="#_21-stripe決済の全設定-完全ガイド" aria-label="Permalink to &quot;21. Stripe決済の全設定（完全ガイド）&quot;">​</a></h1><p>POSLAはStripeを2つの目的で利用しています。</p><ol><li><strong>Stripe Billing</strong> — POSLA自体の月額利用料の課金（テナントがPOSLAに支払う）</li><li><strong>Stripe Connect</strong> — テナントがお客さんから決済を受け取る（カード/オンライン決済）</li></ol><p>本章ではテナント側でやること・POSLA運営側でやることを、どちらも完全な手順で記載します。</p><hr><h2 id="_21-1-全体像" tabindex="-1">21.1 全体像 <a class="header-anchor" href="#_21-1-全体像" aria-label="Permalink to &quot;21.1 全体像&quot;">​</a></h2><h3 id="登場人物" tabindex="-1">登場人物 <a class="header-anchor" href="#登場人物" aria-label="Permalink to &quot;登場人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>役割</th><th>説明</th></tr></thead><tbody><tr><td>POSLA運営（プラスビリーフ）</td><td>Stripeプラットフォーム事業者。Stripe Billing・Stripe Connectの親アカウントを持つ</td></tr><tr><td>テナント（飲食店）</td><td>POSLAに月額料金を支払い、Stripe Connect経由でお客さんから決済を受け取る</td></tr><tr><td>お客さん</td><td>テナントの飲食店で注文し、カード決済する</td></tr></tbody></table><h3 id="お金の流れ" tabindex="-1">お金の流れ <a class="header-anchor" href="#お金の流れ" aria-label="Permalink to &quot;お金の流れ&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>【Stripe Billing】</span></span>
<span class="line"><span>テナント → 月額プラン料金 → Stripe → POSLA運営</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【Stripe Connect】</span></span>
<span class="line"><span>お客さん → カード決済 → Stripe → テナント売上 − POSLA手数料(1.0%) − Stripe決済手数料</span></span></code></pre></div><hr><h2 id="_21-2-stripe-billing-posla月額料金" tabindex="-1">21.2 Stripe Billing（POSLA月額料金） <a class="header-anchor" href="#_21-2-stripe-billing-posla月額料金" aria-label="Permalink to &quot;21.2 Stripe Billing（POSLA月額料金）&quot;">​</a></h2><h3 id="_21-2-1-テナント側の申込み手順" tabindex="-1">21.2.1 テナント側の申込み手順 <a class="header-anchor" href="#_21-2-1-テナント側の申込み手順" aria-label="Permalink to &quot;21.2.1 テナント側の申込み手順&quot;">​</a></h3><ol><li>POSLAのランディングページまたはオーナーダッシュボードの「契約・プラン」タブを開きます</li><li>プランを選択します（standard / pro / enterprise）</li><li>「サブスクリプション開始」ボタンをクリックします</li><li>Stripe Checkoutの決済ページにリダイレクトされます</li><li>クレジットカード情報を入力します</li><li>決済完了後、自動的にPOSLAに戻り、プランが有効化されます</li></ol><h3 id="_21-2-2-プラン変更・解約" tabindex="-1">21.2.2 プラン変更・解約 <a class="header-anchor" href="#_21-2-2-プラン変更・解約" aria-label="Permalink to &quot;21.2.2 プラン変更・解約&quot;">​</a></h3><p><strong>アップグレード（standard → pro 等）：</strong></p><ol><li>「契約・プラン」タブで上位プランを選択</li><li>差額が日割り計算されて即座に課金されます</li><li>新プランの機能が即時有効化されます</li></ol><p><strong>ダウングレード：</strong></p><ol><li>「契約・プラン」タブで下位プランを選択</li><li>現在の課金期間の終了時にダウングレードが反映されます（次回請求から新料金）</li><li>上位プラン専用のタブは期間終了後に非表示になります</li></ol><p><strong>解約：</strong></p><ol><li>「契約・プラン」タブの「サブスクリプションを解約」をクリック</li><li>現在の課金期間の終了時に解約されます</li><li>解約後はPOSLAへのログインはできますが、機能制限モードになります</li></ol><h3 id="_21-2-3-支払い状況の確認" tabindex="-1">21.2.3 支払い状況の確認 <a class="header-anchor" href="#_21-2-3-支払い状況の確認" aria-label="Permalink to &quot;21.2.3 支払い状況の確認&quot;">​</a></h3><p>「契約・プラン」タブで以下が確認できます。</p><ul><li>現在のプラン</li><li>次回請求日</li><li>前回の支払い状況（成功/失敗）</li><li>請求書のダウンロード（Stripe Customer Portal）</li></ul><h3 id="_21-2-4-支払い失敗時の動作" tabindex="-1">21.2.4 支払い失敗時の動作 <a class="header-anchor" href="#_21-2-4-支払い失敗時の動作" aria-label="Permalink to &quot;21.2.4 支払い失敗時の動作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状態</th><th>説明</th></tr></thead><tbody><tr><td>1回目の失敗</td><td>警告メール送信。機能は引き続き利用可能</td></tr><tr><td>3日後に再試行</td><td>Stripeが自動で再課金</td></tr><tr><td>最終失敗（7日後）</td><td><code>subscription_status</code>が<code>past_due</code>に変わり、警告バナー表示</td></tr><tr><td>長期未払い</td><td><code>canceled</code>になり、機能制限モード</td></tr></tbody></table><h3 id="_21-2-5-posla運営側の設定手順" tabindex="-1">21.2.5 POSLA運営側の設定手順 <a class="header-anchor" href="#_21-2-5-posla運営側の設定手順" aria-label="Permalink to &quot;21.2.5 POSLA運営側の設定手順&quot;">​</a></h3><p>POSLA運営（プラスビリーフ）が初期設定時に行う作業です。</p><p><strong>ステップ1：Stripe Dashboardで商品を作成</strong></p><ol><li><a href="https://dashboard.stripe.com/" target="_blank" rel="noreferrer">Stripe Dashboard</a> にログイン</li><li>「商品」→「商品を追加」</li><li>3つの商品を作成： <ul><li>POSLA Standard — 月額 ¥10,000</li><li>POSLA Pro — 月額 ¥20,000〜30,000</li><li>POSLA Enterprise — 月額 ¥50,000</li></ul></li><li>各商品の価格IDを控える（<code>price_xxxx</code> 形式）</li></ol><p><strong>ステップ2：APIキーを取得</strong></p><ol><li>Stripe Dashboard &gt; 開発者 &gt; APIキー</li><li>シークレットキー（<code>sk_live_xxx</code>）を取得</li><li>公開可能キー（<code>pk_live_xxx</code>）を取得</li></ol><p><strong>ステップ3：Webhookエンドポイントを登録</strong></p><ol><li>Stripe Dashboard &gt; 開発者 &gt; Webhooks &gt; 「エンドポイントを追加」</li><li>URL: <code>https://eat.posla.jp/api/subscription/webhook.php</code></li><li>監視イベント： <ul><li><code>checkout.session.completed</code></li><li><code>customer.subscription.updated</code></li><li><code>customer.subscription.deleted</code></li><li><code>invoice.paid</code></li><li><code>invoice.payment_failed</code></li></ul></li><li>Webhook署名シークレット（<code>whsec_xxx</code>）を取得</li></ol><p><strong>ステップ4：POSLA管理画面に入力</strong></p><p>POSLA管理画面（<code>/public/posla-admin/dashboard.html</code>）の「API設定」タブで以下を入力します。</p><table tabindex="0"><thead><tr><th>キー名</th><th>値</th></tr></thead><tbody><tr><td>stripe_secret_key</td><td><code>sk_live_xxx</code></td></tr><tr><td>stripe_publishable_key</td><td><code>pk_live_xxx</code></td></tr><tr><td>stripe_webhook_secret</td><td><code>whsec_xxx</code></td></tr><tr><td>stripe_price_standard</td><td>Standard商品の価格ID</td></tr><tr><td>stripe_price_pro</td><td>Pro商品の価格ID</td></tr><tr><td>stripe_price_enterprise</td><td>Enterprise商品の価格ID</td></tr></tbody></table><p><strong>ステップ5：動作確認</strong></p><ol><li>テストテナントでサブスクリプション開始フローを実行</li><li>Stripe DashboardのWebhookログで全イベントが正常に受信されているか確認</li><li>POSLA側の<code>subscription_events</code>テーブルにイベントが記録されているか確認</li></ol><hr><h2 id="_21-3-stripe-connect-テナントがお客さんから決済を受け取る" tabindex="-1">21.3 Stripe Connect（テナントがお客さんから決済を受け取る） <a class="header-anchor" href="#_21-3-stripe-connect-テナントがお客さんから決済を受け取る" aria-label="Permalink to &quot;21.3 Stripe Connect（テナントがお客さんから決済を受け取る）&quot;">​</a></h2><h3 id="_21-3-1-テナント側の接続手順" tabindex="-1">21.3.1 テナント側の接続手順 <a class="header-anchor" href="#_21-3-1-テナント側の接続手順" aria-label="Permalink to &quot;21.3.1 テナント側の接続手順&quot;">​</a></h3><ol><li>オーナーダッシュボードにログイン</li><li>「決済設定」タブを開く</li><li>「Stripe接続を開始」ボタンをクリック</li><li>POSLAがStripe Express Accountを作成</li><li>Stripeのオンボーディングページにリダイレクト</li><li>以下の情報を入力： <ul><li>事業者情報（法人名・代表者名・住所・電話番号）</li><li>銀行口座情報（入金先）</li><li>本人確認書類（運転免許証・マイナンバーカード等）</li><li>事業内容（飲食店）</li></ul></li><li>Stripeが審査（通常1〜3営業日）</li><li>審査完了後、POSLAの「決済設定」タブで接続状態が「有効」に変わります</li></ol><h3 id="_21-3-2-接続状態の確認" tabindex="-1">21.3.2 接続状態の確認 <a class="header-anchor" href="#_21-3-2-接続状態の確認" aria-label="Permalink to &quot;21.3.2 接続状態の確認&quot;">​</a></h3><p>「決済設定」タブで以下が確認できます。</p><table tabindex="0"><thead><tr><th>項目</th><th>意味</th></tr></thead><tbody><tr><td>charges_enabled</td><td>お客さんからの決済受付が可能か（true/false）</td></tr><tr><td>payouts_enabled</td><td>入金（銀行振込）が有効か</td></tr><tr><td>details_submitted</td><td>必要情報の入力が完了しているか</td></tr></tbody></table><p>すべてがtrueになっている必要があります。いずれかがfalseの場合、Stripeダッシュボードで追加情報の入力が必要です。</p><h3 id="_21-3-3-決済方法の設定" tabindex="-1">21.3.3 決済方法の設定 <a class="header-anchor" href="#_21-3-3-決済方法の設定" aria-label="Permalink to &quot;21.3.3 決済方法の設定&quot;">​</a></h3><p>テナントは店舗設定で利用する決済方法を選択できます。</p><table tabindex="0"><thead><tr><th>決済方法</th><th>説明</th><th>必要な接続</th></tr></thead><tbody><tr><td>現金</td><td>テンキーで入力</td><td>不要</td></tr><tr><td>クレジット（対面）</td><td>Stripe Reader S700</td><td>Stripe Connect</td></tr><tr><td>QR決済（PayPay等）</td><td>外部QR決済アプリで処理</td><td>不要</td></tr><tr><td>セルフレジ（お客さんスマホ）</td><td>Stripe オンライン決済</td><td>Stripe Connect</td></tr></tbody></table><h3 id="_21-3-4-カードリーダー-stripe-reader-s700" tabindex="-1">21.3.4 カードリーダー（Stripe Reader S700） <a class="header-anchor" href="#_21-3-4-カードリーダー-stripe-reader-s700" aria-label="Permalink to &quot;21.3.4 カードリーダー（Stripe Reader S700）&quot;">​</a></h3><p>対面でクレジットカード決済を受ける場合、Stripe Reader S700が必要です。</p><table tabindex="0"><thead><tr><th>項目</th><th>値</th></tr></thead><tbody><tr><td>価格</td><td>¥52,480</td></tr><tr><td>接続方式</td><td>Wi-Fi</td></tr><tr><td>対応プラットフォーム</td><td>Web（Stripe Terminal JS SDK）</td></tr><tr><td>発注方法</td><td>POSLA運営経由でStripeに発注</td></tr></tbody></table><p><strong>セットアップ手順：</strong></p><ol><li>端末を電源に接続し、Wi-Fiに接続</li><li>レジアプリ（<code>/public/kds/register.html</code>）で「カードリーダー接続」ボタンをクリック</li><li>接続トークンが自動発行され、レジアプリがリーダーと通信を開始</li><li>リーダーが「Ready」と表示されたら決済可能</li></ol><p><strong>決済フロー：</strong></p><ol><li>レジでメニューを選択し、合計金額を確定</li><li>「クレジット（対面）」を選択</li><li>カードリーダーに金額が表示される</li><li>お客さんがカードをタッチ/挿入</li><li>決済結果がレジに返される</li><li>成功時：レシートを印刷して完了</li></ol><h3 id="_21-3-5-セルフレジ-お客さんのスマホで決済" tabindex="-1">21.3.5 セルフレジ（お客さんのスマホで決済） <a class="header-anchor" href="#_21-3-5-セルフレジ-お客さんのスマホで決済" aria-label="Permalink to &quot;21.3.5 セルフレジ（お客さんのスマホで決済）&quot;">​</a></h3><p>セルフオーダー画面からお客さんがカード決済する場合です。</p><ol><li>お客さんがカートから「チェックアウト」へ</li><li>決済方法選択画面で「クレジットカード」を選択</li><li>Stripe Elementsの決済フォームが表示される</li><li>カード情報を入力して「支払う」</li><li>決済完了後、注文が自動送信される</li></ol><h3 id="_21-3-6-手数料の仕組み" tabindex="-1">21.3.6 手数料の仕組み <a class="header-anchor" href="#_21-3-6-手数料の仕組み" aria-label="Permalink to &quot;21.3.6 手数料の仕組み&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>お客さんの支払額 = 注文金額</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Stripe が決済を処理</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>テナント受取額 = 注文金額 − POSLA手数料 − Stripe決済手数料</span></span></code></pre></div><table tabindex="0"><thead><tr><th>手数料</th><th>率</th><th>取得者</th></tr></thead><tbody><tr><td>Stripe決済手数料</td><td>3.6%</td><td>Stripe</td></tr><tr><td>POSLA手数料</td><td>1.0%</td><td>POSLA運営</td></tr></tbody></table><p><strong>計算例（¥3,000の決済）：</strong></p><table tabindex="0"><thead><tr><th>項目</th><th>金額</th></tr></thead><tbody><tr><td>決済金額</td><td>¥3,000</td></tr><tr><td>Stripe決済手数料（3.6%）</td><td>¥108</td></tr><tr><td>POSLA手数料（1.0%）</td><td>¥30</td></tr><tr><td>テナント受取額</td><td>¥2,862</td></tr></tbody></table><p>POSLA手数料は <code>ceil(決済金額 × 1.0 / 100)</code> で計算され、最低¥1です。</p><h3 id="_21-3-7-入金サイクル" tabindex="-1">21.3.7 入金サイクル <a class="header-anchor" href="#_21-3-7-入金サイクル" aria-label="Permalink to &quot;21.3.7 入金サイクル&quot;">​</a></h3><ul><li>決済から約7日後にテナント指定の銀行口座に自動入金されます</li><li>入金サイクルはStripe Dashboardで確認・変更できます</li><li>週次入金、月次入金などの設定が可能</li></ul><h3 id="_21-3-8-posla運営側の設定手順" tabindex="-1">21.3.8 POSLA運営側の設定手順 <a class="header-anchor" href="#_21-3-8-posla運営側の設定手順" aria-label="Permalink to &quot;21.3.8 POSLA運営側の設定手順&quot;">​</a></h3><p><strong>ステップ1：Stripe Connectプラットフォーム登録</strong></p><ol><li>Stripe Dashboardで「Connect」を有効化</li><li>プラットフォーム情報を入力（POSLAのビジネス情報）</li><li>対応国：日本（JP）</li><li>アカウントタイプ：Express</li></ol><p><strong>ステップ2：Connect手数料の設定</strong></p><p>POSLA管理画面の「API設定」タブで以下を設定します。</p><table tabindex="0"><thead><tr><th>キー名</th><th>デフォルト</th><th>説明</th></tr></thead><tbody><tr><td>connect_application_fee_percent</td><td>1.0</td><td>POSLA手数料率（%）</td></tr></tbody></table><p><strong>ステップ3：Stripe Terminal（カードリーダー）用の設定</strong></p><ul><li>Stripeダッシュボードで Terminal 機能を有効化</li><li>POSLA側は接続トークン発行エンドポイント（<code>POST /api/connect/terminal-token.php</code>）で対応</li></ul><p><strong>ステップ4：テナントの接続状態を定期確認</strong></p><ul><li><code>stripe_connect_account_id</code> が設定されているテナントに対して、Stripe APIで最新の <code>charges_enabled</code>/<code>payouts_enabled</code>/<code>details_submitted</code> を取得</li><li>POSLA管理画面の「テナント管理」タブで接続状態を一覧表示</li></ul><hr><h2 id="_21-4-データベース構造" tabindex="-1">21.4 データベース構造 <a class="header-anchor" href="#_21-4-データベース構造" aria-label="Permalink to &quot;21.4 データベース構造&quot;">​</a></h2><h3 id="テナントテーブルのstripe関連フィールド" tabindex="-1">テナントテーブルのStripe関連フィールド <a class="header-anchor" href="#テナントテーブルのstripe関連フィールド" aria-label="Permalink to &quot;テナントテーブルのStripe関連フィールド&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>型</th><th>説明</th></tr></thead><tbody><tr><td>stripe_customer_id</td><td>VARCHAR(50)</td><td>StripeカスタマーID（<code>cus_xxx</code>）</td></tr><tr><td>stripe_subscription_id</td><td>VARCHAR(50)</td><td>サブスクリプションID（<code>sub_xxx</code>）</td></tr><tr><td>subscription_status</td><td>ENUM</td><td>none/trialing/active/past_due/canceled</td></tr><tr><td>current_period_end</td><td>DATETIME</td><td>現在の課金期間終了日</td></tr><tr><td>stripe_connect_account_id</td><td>VARCHAR(100)</td><td>Connect アカウントID（<code>acct_xxx</code>）</td></tr><tr><td>connect_onboarding_complete</td><td>TINYINT(1)</td><td>オンボーディング完了フラグ</td></tr></tbody></table><h3 id="subscription-events-テーブル" tabindex="-1">subscription_events テーブル <a class="header-anchor" href="#subscription-events-テーブル" aria-label="Permalink to &quot;subscription_events テーブル&quot;">​</a></h3><p>全Webhookイベントの受信ログです。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>event_id</td><td>UUID</td></tr><tr><td>tenant_id</td><td>対象テナント</td></tr><tr><td>event_type</td><td>Webhookイベントタイプ</td></tr><tr><td>stripe_event_id</td><td>StripeのイベントID</td></tr><tr><td>data</td><td>イベントデータ（JSON）</td></tr><tr><td>created_at</td><td>受信日時</td></tr></tbody></table><hr><h2 id="_21-5-トラブルシューティング" tabindex="-1">21.5 トラブルシューティング <a class="header-anchor" href="#_21-5-トラブルシューティング" aria-label="Permalink to &quot;21.5 トラブルシューティング&quot;">​</a></h2><h3 id="stripe-billing関連" tabindex="-1">Stripe Billing関連 <a class="header-anchor" href="#stripe-billing関連" aria-label="Permalink to &quot;Stripe Billing関連&quot;">​</a></h3><table tabindex="0"><thead><tr><th>問題</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>サブスクリプション開始後にプランが反映されない</td><td>Webhookが届いていない</td><td>Stripe Dashboardでイベントログを確認。再送信</td></tr><tr><td>請求書が発行されない</td><td>メールアドレス未登録</td><td>テナント設定でメールアドレスを登録</td></tr><tr><td>カード決済が失敗する</td><td>カード与信問題</td><td>Stripe Customer Portalで別カードに変更</td></tr></tbody></table><h3 id="stripe-connect関連" tabindex="-1">Stripe Connect関連 <a class="header-anchor" href="#stripe-connect関連" aria-label="Permalink to &quot;Stripe Connect関連&quot;">​</a></h3><table tabindex="0"><thead><tr><th>問題</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>接続状態が「無効」のまま</td><td>オンボーディング未完了</td><td>Stripeから届いたメールの指示に従って情報を追加入力</td></tr><tr><td><code>charges_enabled</code>がfalse</td><td>審査中または書類不備</td><td>Stripe Dashboardでメッセージを確認</td></tr><tr><td>カードリーダー接続できない</td><td>Wi-Fi切断・ファームウェア古い</td><td>リーダー再起動・ファームウェア更新</td></tr><tr><td>決済完了するが注文が記録されない</td><td>Webhook失敗</td><td><code>subscription_events</code>テーブルと<code>audit_log</code>を確認</td></tr></tbody></table>`,91)])])}const _=e(r,[["render",l]]);export{b as __pageData,_ as default};
